import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;

public class SecureCommandExecution {

    public static void main(String[] args) {
        try {
            BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));
            System.out.print("Enter a command to execute: ");
            String command = reader.readLine();

            // Split the user input into command and arguments
            String[] cmdArray = command.split("\\s+");

            // Create ProcessBuilder instance with the command and arguments
            ProcessBuilder processBuilder = new ProcessBuilder(cmdArray);

            // Start the process
            Process process = processBuilder.start();

            // Read and display output from the process
            BufferedReader processOutputReader = new BufferedReader(new InputStreamReader(process.getInputStream()));
            String line;
            while ((line = processOutputReader.readLine()) != null) {
                System.out.println(line);
            }

        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

